body:
.select2-container {
  box-sizing: border-box;
  display: inline-block;
  margin: 0;
  position: relative;
  vertical-align: middle; }
  .select2-container .select2-selection--single {
    box-sizing: border-box;
    cursor: pointer;
    display: block;
    height: auto;
    user-select: none;
    -webkit-user-select: none; }
    .select2-container .select2-selection--single .select2-selection__rendered {
      display: block;
      padding-left: 8px;
      padding-right: 20px;
      overflow: hidden;
      text-overflow: ellipsis;
      white-space: nowrap; }
    .select2-container .select2-selection--single .select2-selection__clear {
      position: relative; }
  .select2-container[dir="rtl"] .select2-selection--single .select2-selection__rendered {
    padding-right: 8px;
    padding-left: 20px; }
  .select2-container .select2-selection--multiple {
    box-sizing: border-box;
    cursor: pointer;
    display: block;
    min-height: 32px;
    user-select: none;
    -webkit-user-select: none; }
    .select2-container .select2-selection--multiple .select2-selection__rendered {
      display: inline-block;
      overflow: hidden;
      padding-left: 8px;
      text-overflow: ellipsis;
      white-space: nowrap; }
  .select2-container .select2-search--inline {
    float: left; }
    .select2-container .select2-search--inline .select2-search__field {
      box-sizing: border-box;
      border: none;
      font-size: 100%;
      margin-top: 5px;
      padding: 0; }
      .select2-container .select2-search--inline .select2-search__field::-webkit-search-cancel-button {
        -webkit-appearance: none; }

.select2-dropdown {
  background-color: white;
  border: 1px solid #aaa;
  border-radius: 4px;
  box-sizing: border-box;
  display: block;
  position: absolute;
  left: -100000px;
  width: 100%;
  z-index: 1051; }

.select2-results {
  display: block; }

.select2-results__options {
  list-style: none;
  margin: 0;
  padding: 0; }

.select2-results__option {
  padding: 6px;
  user-select: none;
  -webkit-user-select: none; }
  .select2-results__option[aria-selected] {
    cursor: pointer; }

.select2-container--open .select2-dropdown {
  left: 0; }

.select2-container--open .select2-dropdown--above {
  border-bottom: none;
  border-bottom-left-radius: 0;
  border-bottom-right-radius: 0; }

.select2-container--open .select2-dropdown--below {
  border-top: none;
  border-top-left-radius: 0;
  border-top-right-radius: 0; }

.select2-search--dropdown {
  display: block;
  padding: 4px; }
  .select2-search--dropdown .select2-search__field {
    padding: 4px;
    width: 100%;
    box-sizing: border-box; }
    .select2-search--dropdown .select2-search__field::-webkit-search-cancel-button {
      -webkit-appearance: none; }
  .select2-search--dropdown.select2-search--hide {
    display: none; }

.select2-close-mask {
  border: 0;
  margin: 0;
  padding: 0;
  display: block;
  position: fixed;
  left: 0;
  top: 0;
  min-height: 100%;
  min-width: 100%;
  height: auto;
  width: auto;
  opacity: 0;
  z-index: 99;
  background-color: #fff;
  filter: alpha(opacity=0); }

.select2-hidden-accessible {
  border: 0 !important;
  clip: rect(0 0 0 0) !important;
  -webkit-clip-path: inset(50%) !important;
  clip-path: inset(50%) !important;
  height: 1px !important;
  overflow: hidden !important;
  padding: 0 !important;
  position: absolute !important;
  width: 1px !important;
  white-space: nowrap !important; }

.select2-container--default .select2-selection--single {
  background-color: #fff;
  /*border: 1px solid #aaa;*/
  border-radius: 4px; }
  .select2-container--default .select2-selection--single .select2-selection__rendered {
    color: #444;
    /*line-height: 28px;*/ }
  .select2-container--default .select2-selection--single .select2-selection__clear {
    cursor: pointer;
    float: right;
    font-weight: bold; }
  .select2-container--default .select2-selection--single .select2-selection__placeholder {
    color: #999; }
  .select2-container--default .select2-selection--single .select2-selection__arrow {
    height: 26px;
    position: absolute;
    /*top: 1px;*/
    right: 1px;
    width: 20px; }
    .select2-container--default .select2-selection--single .select2-selection__arrow b {
      border-color: #888 transparent transparent transparent;
      border-style: solid;
      border-width: 5px 4px 0 4px;
      height: 0;
      left: 50%;
      margin-left: -4px;
      margin-top: -2px;
      position: absolute;
      top: 50%;
      width: 0; }

.select2-container--default[dir="rtl"] .select2-selection--single .select2-selection__clear {
  float: left; }

.select2-container--default[dir="rtl"] .select2-selection--single .select2-selection__arrow {
  left: 1px;
  right: auto; }

.select2-container--default.select2-container--disabled .select2-selection--single {
  background-color: #eee;
  cursor: default; }
  .select2-container--default.select2-container--disabled .select2-selection--single .select2-selection__clear

:root {
    --yellow-one: #FFCC00;
    --yellow-two: #CB9700;
    --gray-one: #898989;
    --gray-two: #F2F2F2;
    --gray-three: #F9F9F9;
    --gray-four: #EBEBEB;
    --gray-five: #EDEDED;
    --gray-six: #615757;
    --gray-seven: #575757;
    --gray-eight: #CCCCCC;
    --gray-nine: #262626;
    --gray-ten: #D4D4D4;
    --gray-eleven: #888888;
    --gray-twelve: #C1C1C1;
    --gray-thirteen: #DADADA;
    --gray-fourteen: #BBBBBB;
    --green-one: #27AA4C;
    --green-two: #25A048;
    --green-three: #98B78E;
    --red-ifood: #EA1D2C;
    --red-light-ifood: #FFEFF0;
    --red-border-ifood: #CAB0B2;
    --red-uaiRango: #FF3B00;
    --green-uaiRango: #007F2C;
    --red-one: #E84646;
    --blue-one: #80BAFF;
}

body {
    font-family: 'Montserrat';
    margin-left: 117px;
    overflow-y: scroll;
    display: flex;
    flex-direction: column;
    height: 100vh;
}

body>main {
    width: 1000px;
    max-width: 100%;
    margin: auto;
    padding: 24px;
    padding-bottom: 82px;
    flex-grow: 1;
}

span.dot {
    height: 10px;
    width: 10px;
    background-color: #bbb;
    border-radius: 50%;
    display: inline-block;
    background-color: #EBEBEB;
}

a,
a:hover,
a:active {
    color: #000;
    text-decoration: none;
}

[v-cloak] {
    display: none;
}

.line-clamp-2 {
    display: -webkit-box;
    overflow: hidden;
    -webkit-box-orient: vertical;
    -webkit-line-clamp: 2;
}

.line-clamp-3 {
    display: -webkit-box;
    overflow: hidden;
    -webkit-box-orient: vertical;
    -webkit-line-clamp: 3;
}

.bg-ice {
    background-color: #F6F6F6;
}

.text-yellow {
    color: var(--yellow-one);
}

.text-gray {
    color: var(--gray-one);
}

.text-black {
    color: #000000;
}

.font-weight-semi-bold {
    font-weight: 600 !important;
}

.font-weight-medium {
    font-weight: 500 !important;
}

.bordered-yellow-large {
    border-left: 5px solid var(--yellow-one);
}

.bg-yellow {
    background-color: var(--yellow-one) !important;
}

.bg-gray-three {
    background-color: var(--gray-three);
}

.oculto {
    display: none !important;
}

.justify-center {
    display: flex;
    justify-content: center;
}

.items-center {
    display: flex;
    align-items: center;
}

.center {
    display: flex;
    justify-content: center;
    align-items: center;
}

.height-fit-content {
    height: fit-content;
}

.gap-3 {
    gap: 16px;
}

.line-height-sm {
    line-height: 14px;
}

.text-2xs {
    font-size: 10px;
}

.text-xs {
    font-size: 12px;
}

.text-sm {
    font-size: 14px;
}

.text-md {
    font-size: 16px;
}

.text-lg {
    font-size: 18px;
}

.text-xl {
    font-size: 20px;
}

.text-2xl {
    font-size: 22px;
}

.text-3xl {
    font-size: 24px;
}

.text-4xl {
    font-size: 26px;
}

.text-5xl {
    font-size: 28px;
}

.space-y-1>*+* {
    margin-top: 4px;
}

.space-y-2>*+* {
    margin-top: 8px;
}

.space-y-3>*+* {
    margin-top: 16px;
}

.space-y-4>*+* {
    margin-top: 24px;
}

.space-y-5>*+* {
    margin-top: 48px;
}

.space-x-1>*+* {
    margin-left: 4px;
}

.space-x-2>*+* {
    margin-left: 8px;
}

.space-x-3>*+* {
    margin-left: 16px;
}

.space-x-4>*+* {
    margin-left: 24px;
}

.space-x-5>*+* {
    margin-left: 48px;
}

.divide-y>*+* {
    border-top: 1px solid var(--gray-thirteen);
}

.flex-unset {
    flex: unset !important;
}

.flex-1 {
    flex: 1 !important;
}

.w-unset {
    width: unset !important;
}

.fa-chevron-down {
    transition: 150ms;
    background-color: #F9F9F9;
    border: none;
    outline: none;
}

.fa-chevron-down[aria-expanded="true"] {
    transform: rotate(180deg);
    border: none;
    outline: none;
}

.fa-chevron-down[aria-expanded="false"] {
    transform: rotate(360deg);
    border: none;
    outline: none;
}

a.text-underline,
a.text-underline:hover,
a.text-underline:active {
    text-decoration: underline;
}

.cursor-pointer {
    cursor: pointer;
}

.feather {
    width: 16px;
    height: 16px;
    vertical-align: text-bottom;
}

.alert {
    display: flex;
    align-items: center;
    gap: 20px;
}

.alert>* {
    flex: 1;
}

.alert>.close {
    flex: 0;
    align-self: start;
}

.input-change-password {

}

.page-link,
.page-link:hover,
.page-item.active .page-link {
    color: black;
}

.page-item.active .page-link {
    border-color: var(--yellow-one);
    background-color: var(--yellow-one);
}

.input-group {
    align-items: center;
}

.input-group-prepend {
    position: absolute;
    z-index: 4;
    padding-left: 16px;
}

.input-group-prepend+.form-control {
    padding-left: 40px;
}

.input-group-append {
    position: absolute;
    right: 0;
    z-index: 4;
    padding-right: 16px;
}

.input-group-append+.form-control {
    padding-right: 40px;
}

.btn.disabled,
.btn:disabled {
    opacity: .3;
}

.btn-outline-yellow {
    border: 2px solid;
    border-color: var(--yellow-one);
    background-color: #FFFFFF;
    color: #000000;
}

.btn-outline-yellow:hover {
    border-color: var(--yellow-one);
    background-color: #FFFFFF;
    color: #000000;
}

