        justify-content: center;
        padding: 0;
        margin: 0;
    }

    .navbar-nav .nav-item.dropdown .nav-link {
        width: 100%;
        max-width: 20.5rem; /* 328px */
        height: 2.375rem; /* 38px */
        padding-top: 0.5rem; /* 8px */
