/* EstilizaÃ§ÃĢo do botÃĢo Novo Painel */
.sparkles-navbar {
    width: 147px;
    height: 38px;
    padding: 8px 16px;
    gap: 10px;
    border-radius: 8px;
    border: 1px solid #FFCC00;
    background-color: #FFCC0029;
    opacity: 1;
    transition: all 0.3s ease;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
}

/* Container dos botÃĩes da navbar */
.navbar-buttons-group {
    display: flex;
    align-items: center;
    gap: 1rem; /* EspaÃ§amento igual entre todos os botÃĩes */
}

@media (min-width: 768px) {
    .navbar {
        display: flex !important;
        flex-wrap: nowrap;
        align-items: center;
        justify-content: flex-end;
    }

    .navbar-buttons-group {
        display: flex;
        align-items: center;
        gap: 1rem;
        flex: 0 0 auto;
        margin-left: auto;
        margin-right: 1rem;
    }

    /* Remover margens dos botÃĩes individuais para usar gap */
    .navbar-buttons-group > .sparkles-navbar,
    .navbar-buttons-group > .avisos,
    .navbar-buttons-group > .saldoEmpresa,
    .navbar-buttons-group > .guia-navbar {
        margin-left: 0 !important;
        margin-right: 0 !important;
    }

    /* Garantir que os botÃĩes dentro do grupo nÃĢo tenham margens */
    .navbar-buttons-group .sparkles-navbar {
        margin: 0;
    }

    /* Menu alinhado Ã  direita, depois dos botÃĩes */
    .navbar #navbarSupportedContent {
        margin-left: 0 !important;
        flex: 0 0 auto;
    }

    .navbar #navbarSupportedContent .navbar-nav {
        margin-left: 0 !important;
    }

    .navbar .navbar-toggler {
        order: 999;
    }
}

.sparkles-navbar:hover {
    background-color: #FFCC0040;
    border-color: #FFD700;
}

.sparkles-navbar .nav-link {
    padding: 0;
    display: flex;
    align-items: center;
    gap: 10px;
    color: #333 !important;
    font-weight: 500;
    font-size: 14px;
    text-decoration: none;
}

.sparkles-navbar .fa-sparkles {
    color: #FFCC00;
    font-size: 16px;
}

